// URLs des blogs concurrents à surveiller
const competitors = [
  {
    name: 'Factorial',
    blog_url: 'https://factorialhr.fr/blog',
    rss_url: 'https://factorialhr.fr/blog/feed',
    strengths: 'SIRH tout-en-un, UX moderne',
    weaknesses: 'Faible sur le droit social français, contenu souvent traduit de l\'espagnol'
  },
  {
    name: 'Lucca',
    blog_url: 'https://www.lucca.fr/magazine',
    rss_url: 'https://www.lucca.fr/magazine/feed',
    strengths: 'Contenu RH de qualité, bon SEO existant',
    weaknesses: 'Cible entreprises 50+, pas spécialisé paie TPE'
  },
  {
    name: 'Cegid',
    blog_url: 'https://www.cegid.com/fr/blog',
    rss_url: 'https://www.cegid.com/fr/blog/feed',
    strengths: 'Large couverture métier, expertise comptable',
    weaknesses: 'Contenu corporate/générique, pricing opaque'
  },
  {
    name: 'Sage',
    blog_url: 'https://www.sage.com/fr-fr/blog',
    rss_url: 'https://www.sage.com/fr-fr/blog/feed',
    strengths: 'Base installée massive, notoriété',
    weaknesses: 'Image vieillissante, contenu peu engageant'
  }
];

return competitors.map(c => ({ json: c }));

// Parser le RSS du concurrent et construire le body OpenAI
const competitor = $('Par concurrent').first().json;
const xmlText = $input.first().json.data || $input.first().json.body || '';

let articlesList = 'Aucun article detecte via RSS';

if (xmlText && typeof xmlText === 'string' && xmlText.length >= 100) {
  const itemRegex = /<item>(.*?)<\/item>/gs;
  const titleRegex = /<title><!\[CDATA\[(.*?)\]\]><\/title>|<title>(.*?)<\/title>/;
  const dateRegex = /<pubDate>(.*?)<\/pubDate>/;
  const items = [];
  let match;
  while ((match = itemRegex.exec(xmlText)) !== null) {
    const block = match[1];
    const titleMatch = block.match(titleRegex);
    const dateMatch = block.match(dateRegex);
    if (titleMatch) {
      const title = (titleMatch[1] || titleMatch[2] || '').trim();
      const pubDate = dateMatch ? new Date(dateMatch[1].trim()) : null;
      const thirtyDaysAgo = new Date();
      thirtyDaysAgo.setDate(thirtyDaysAgo.getDate() - 30);
      if (!pubDate || pubDate >= thirtyDaysAgo) items.push(title);
    }
  }
  const keywords = ['paie','salaire','cotisation','smic','travail','emploi','rh','embauche','licenciement','bulletin','indemnite','prime','teletravail','formation','convention','salarie','employeur','logiciel'];
  const relevant = items.filter(t => { const l = t.toLowerCase().normalize('NFD').replace(/[\u0300-\u036f]/g,''); return keywords.some(kw => l.includes(kw)); }).slice(0,10);
  if (relevant.length > 0) articlesList = relevant.map(t => '- ' + t).join('\n');
}

// Construire le body OpenAI avec JSON.stringify (echappe tout correctement)
const userPrompt = 'Analyse les articles recents de ' + competitor.name + ' (concurrent de PayFit en paie/RH).\n\nForces : ' + (competitor.strengths || '') + '\nFaiblesses : ' + (competitor.weaknesses || '') + '\n\nArticles recents :\n' + articlesList + '\n\nGenere en JSON valide (sans markdown) :\n{\n  "competitor": "nom",\n  "content_strategy": "resume en 1 phrase de leur strategie contenu",\n  "topics_they_cover": ["3-5 sujets principaux couverts"],\n  "content_gaps": [\n    {\n      "topic": "sujet mal couvert ou absent",\n      "opportunity": "pourquoi PayFit peut faire mieux",\n      "suggested_keyword": "mot-cle cible pour PayFit",\n      "priority": "high" ou "medium"\n    }\n  ],\n  "threats": ["sujets ou ce concurrent est fort et ou PayFit doit reagir"]\n}';

const openaiBody = {
  model: 'gpt-4o-mini',
  temperature: 0.4,
  messages: [
    { role: 'system', content: 'Tu es un analyste SEO concurrentiel pour PayFit. Tu analyses les contenus des concurrents pour identifier des opportunites SEO que PayFit peut exploiter.' },
    { role: 'user', content: userPrompt }
  ]
};

return [{ json: { 
  competitor: competitor.name,
  strengths: competitor.strengths,
  weaknesses: competitor.weaknesses,
  openaiBody: openaiBody
} }];

// Parser l'analyse concurrentielle et la formater pour le webhook
const competitor = $('Par concurrent').first().json;
const response = $input.first().json;
const content = response.choices?.[0]?.message?.content || '{}';
const cleaned = content.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim();

let analysis;
try {
  analysis = JSON.parse(cleaned);
} catch {
  analysis = {
    competitor: competitor.name,
    content_strategy: 'Analyse non disponible',
    topics_they_cover: [],
    content_gaps: [],
    threats: []
  };
}

// Creer des entrees benchmark pour chaque gap identifie
const benchmarkEntries = (analysis.content_gaps || []).map(gap => ({
  type: 'benchmark',
  data: {
    competitor: analysis.competitor,
    keyword: gap.suggested_keyword || gap.topic,
    position: null,
    url: null,
    content_type: 'content_gap',
    notes: JSON.stringify({
      topic: gap.topic,
      opportunity: gap.opportunity,
      priority: gap.priority,
      content_strategy: analysis.content_strategy,
      threats: analysis.threats
    })
  }
}));

// Creer des trends depuis les content gaps haute priorite
// IMPORTANT: score_total est GENERATED dans Supabase, ne PAS l'envoyer
const trendEntries = (analysis.content_gaps || [])
  .filter(gap => gap.priority === 'high')
  .map(gap => ({
    type: 'trend',
    data: {
      question: (gap.suggested_keyword || gap.topic) + ' : guide complet pour TPE/PME 2026',
      source: 'Veille concurrentielle - ' + analysis.competitor,
      signal: 'Content gap detecte : ' + (gap.opportunity || 'opportunite identifiee'),
      score_novelty: 4,
      score_payfit_relevance: 4,
      score_volume: 3,
      icp_target: 'ICP 1+2',
      suggested_format: 'Article pilier + FAQ',
      status: 'new'
    }
  }));

const allEntries = [...benchmarkEntries, ...trendEntries];

return allEntries.length > 0 
  ? allEntries.map(e => ({ json: e }))
  : [{ json: { type: 'benchmark', data: { competitor: analysis.competitor, keyword: 'no-gap-found', notes: 'Aucun gap significatif detecte' } } }];
